computed.formula:
const RUT_ESTRICTO_REGEX = /^\d{7,8}-[0-9kK]$/;

function calcularDv(cuerpo) {
  if (!/^\d+$/.test(cuerpo)) {
    throw new Error('El cuerpo del RUT debe contener solo dígitos.');
  }

  let suma = 0;
  let factor = 2;

  for (let i = cuerpo.length - 1; i >= 0; i--) {
    const dig = cuerpo.charCodeAt(i) - 48; // '0' = 48
    suma += dig * factor;
    factor = factor === 7 ? 2 : factor + 1;
  }

  const mod = 11 - (suma % 11);
  if (mod === 11) return '0';
  if (mod === 10) return 'K';
  return String.fromCharCode(48 + mod);
}

function validarRut(rutCompleto) {
  if (typeof rutCompleto !== 'string') return false;

  if (!RUT_ESTRICTO_REGEX.test(rutCompleto)) return false;

  const [cuerpo, dvTexto] = rutCompleto.split('-');
  const dv = dvTexto.toUpperCase();

  return calcularDv(cuerpo) === dv;
}

function isFilled(value) {
  return value !== null && value !== undefined && value.toString().trim() !== "";
}

setTimeout(() => {
  const modalComponent = document.querySelector(
    '[custom-css-selector="btn_preventivo"]'
  );
  if (!modalComponent || !modalComponent.__vue__) return;

  const vueInstance = modalComponent.__vue__;

  vueInstance.$root.$on("bv::modal::show", (bvEvent, modalId) => {
    const modal = bvEvent.vueTarget;

    if (modalId === "modal_preventivo") {
      modal.onOk = () => {
        const loader = document.getElementById("global-loader-overlay");
        const submitBtn = document.querySelector(
          'button[name="btn_submit_real"]'
        );

        const frmAA_rutAseguradoAd_1 = this.frmAA_rutAseguradoAd_1;
        const frmAA_rutAseguradoAd_2 = this.frmAA_rutAseguradoAd_2;
        const frmAA_rutAseguradoAd_3 = this.frmAA_rutAseguradoAd_3;
        const frmAA_rutAseguradoAd_4 = this.frmAA_rutAseguradoAd_4;
        const frmAA_rutAseguradoAd_5 = this.frmAA_rutAseguradoAd_5;
        const frmDC_rutContratante = this.frmDC_rutContratante;

        let rutValidation = false;

        const rutFields = [
          frmDC_rutContratante,
          frmAA_rutAseguradoAd_1,
          frmAA_rutAseguradoAd_2,
          frmAA_rutAseguradoAd_3,
          frmAA_rutAseguradoAd_4,
          frmAA_rutAseguradoAd_5
        ];

        for (const field of rutFields) {
          if (!isFilled(field)) continue;     // <-- Solo valida si NO está vacío

          if (validarRut(field) === false) {
            rutValidation = true;
            break;
          }
        }

        if (rutValidation) {
          vueInstance.$root.$bvModal.show("modal_alert_rut");
          modal.hide();
          setTimeout(() => {
            if (loader) {
              loader.classList.remove("show");
            }
          }, 350);
          return;
        }

        // Validación de errores visibles ANTES del submit
        const erroresVisibles = Array.from(
          document.querySelectorAll(".invalid-feedback")
        ).filter((div) => {
          const visible = div.offsetParent !== null;
          const mensaje = div.textContent.trim().toLowerCase();
          return (
            visible &&
            (mensaje.includes("campo requerido") ||
              mensaje.includes("debe ser") ||
              mensaje.includes("debe ingresar") ||
              mensaje.includes("debe tener") ||
              mensaje.includes("para continuar") ||
              mensaje.includes("la fecha no puede") ||
              mensaje.includes("la fecha debe estar") ||
              mensaje.includes("el valor debe estar entre") ||
              mensaje.includes("los ingresos proyectados no deben") ||
              mensaje.includes("valor inv") ||
              mensaje.includes("required") ||
              mensaje.includes("must have at ") ||
              mensaje.includes("invalid value"))
          );
        });

        //console.log("Errores visibles encontrados antes de submit:", erroresVisibles.length);

        if (erroresVisibles.length > 0) {
          if (loader) loader.classList.remove("show");
          vueInstance.$root.$bvModal.show("modal_accion_requerida");
          modal.hide();
          return; // NO submit
        }

        if (submitBtn) submitBtn.click();
        loader.classList.add("show");

        modal.hide();
      };
    }
  });
}, 500);

const SUBPRODUCTOS = {
  Servicios: "48110",
  Construccion: "48111",
  Eventos: "48112",
  Serviu: "48114",
  MOP: "48115"
};

const subproductoId = this.frmIG_idSubProducto;

// RC Evento
if (subproductoId === SUBPRODUCTOS.Eventos) {
  return "DATOS DEL EVENTO";
}

// RC Construcción, MOP y SERVIU
if (
  subproductoId === SUBPRODUCTOS.Construccion ||
  subproductoId === SUBPRODUCTOS.MOP ||
